function maxKSubarraysProduct(a, k) {
  const n = a.length;
  const pref = new Array(n + 1).fill(0);
  for (let i = 1; i <= n; i++) pref[i] = pref[i-1] + a[i-1];
  const dp = Array.from({ length: n + 1 }, () => new Array(k + 1).fill(-Infinity));
  const pick = Array.from({ length: n + 1 }, () => new Array(k + 1).fill(-1));
  dp[0][0] = 0;
  for (let i = 1; i <= n; i++) {
    for (let t = 1; t <= k; t++) {
      dp[i][t] = dp[i-1][t];
      for (let j = 1; j <= i; j++) {
        const val = dp[j-1][t-1] + (i - j + 1) * (pref[i] - pref[j-1]);
        if (val > dp[i][t]) {
          dp[i][t] = val;
          pick[i][t] = j;
        }
      }
    }
  }
  // reconstruction omitted for brevity
  return dp[n][k];
}
```

