## Code Example

```javascript
function maxNonCrossingPairs(A, k){
  const n = A.length;
  const NEG = -1e15;
  const dp = Array.from({length: n}, () => Array(k+1).fill(NEG));
  const take = Array.from({length: n}, () => Array(k+1).fill(-1));
  for(let i=0;i<n;i++) dp[i][0] = 0;
  for(let i=0;i<n;i++){
    for(let t=1;t<=k;t++){
      let best = i>0 ? dp[i-1][t] : 0;
      let bestJ = -1;
      for(let j=0;j<i;j++){
        const left = (j>=1) ? dp[j-1][t-1] : (t-1===0 ? 0 : NEG);
        const val = left + Math.abs(A[i]-A[j]);
        if(val > best){ best = val; bestJ = j; }
      }
      dp[i][t] = best;
      take[i][t] = bestJ;
    }
  }
  // reconstruction sketch (omitted for brevity)
  return { value: dp[n-1][k], pairs: [] };
}
``` 

