## Why This Is Asked
Introduces a grid-path DP with a bounded number of teleports, forcing state compression and a 2D prefix max to keep complexity at O(KRC). It tests correctness, backtracking, and memory considerations beyond standard path DP.

## Key Concepts
- DP on grid with at most k teleports
- 2D prefix max to propagate bestPrev for teleport transitions
- Reconstruction: store choice or re-run DP with pointers

## Code Example
```javascript
function maxEnergy(grid, k) {
  const R = grid.length, C = grid[0].length;
  const NEG = -Infinity;
  let dpPrev = Array.from({length:R}, () => Array(C).fill(NEG));
  dpPrev[0][0] = grid[0][0];
  for (let t = 1; t <= k; t++) {
    const bestPrev = Array.from({length:R}, () => Array(C).fill(NEG));
    for (let r = 0; r < R; r++) {
      for (let c = 0; c < C; c++) {
        bestPrev[r][c] = dpPrev[r][c];
        if (r > 0) bestPrev[r][c] = Math.max(bestPrev[r][c], bestPrev[r-1][c]);
        if (c > 0) bestPrev[r][c] = Math.max(bestPrev[r][c], bestPrev[r][c-1]);
      }
    }
    const dpCurr = Array.from({length:R}, () => Array(C).fill(NEG));
    for (let r = 0; r < R; r++) {
      for (let c = 0; c < C; c++) {
        if (r === 0 && c === 0) continue;
        let best = NEG;
        if (r > 0) best = Math.max(best, dpCurr[r-1][c]);
        if (c > 0) best = Math.max(best, dpCurr[r][c-1]);
        if (bestPrev[r][c] !== NEG) best = Math.max(best, bestPrev[r][c]);
        if (best !== NEG) dpCurr[r][c] = best + grid[r][c];
      }
    }
    dpPrev = dpCurr;
  }
  return dpPrev[R-1][C-1];
}
```

